class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        es_app: ElasticsearchApp,
        service: str = "app",
        environment: str = "prod",
        host: str = "",
        flush_interval: float = 1.0,
        max_batch_size: int = 500,
        max_queue_size: int = 10000,
        drop_on_full: bool = True,
        index: Optional[str] = None,
    ):
        super().__init__()
        self.es_app = es_app
        self.service = service
        self.environment = environment
        self.host = host or os.getenv("HOSTNAME", "")
        self.flush_interval = float(flush_interval)
        self.max_batch_size = int(max_batch_size)
        self.max_queue_size = int(max_queue_size)
        self.drop_on_full = bool(drop_on_full)
        self.index = index
        self._q: "queue.Queue[Dict[str, Any]]" = queue.Queue(maxsize=self.max_queue_size)
        self._stop = threading.Event()
        self._worker = threading.Thread(target=self._run, name="es-log-handler", daemon=True)
        self._worker.start()
        atexit.register(self.close)

    def emit(self, record: logging.LogRecord) -> None:
        try:
            msg = record.getMessage()
        except Exception:
            msg = ensure_str(getattr(record, "msg", ""))

        fields = {}
        for k, v in record.__dict__.items():
            if k in (
                "name",
                "msg",
                "args",
                "levelname",
                "levelno",
                "pathname",
                "filename",
                "module",
                "exc_info",
                "exc_text",
                "stack_info",
                "lineno",
                "funcName",
                "created",
                "msecs",
                "relativeCreated",
                "thread",
                "threadName",
                "processName",
                "process",
            ):
                continue
            try:
                json.dumps(v, default=str)
                fields[k] = v
            except Exception:
                fields[k] = ensure_str(v)

        if record.exc_info:
            fields["exception"] = self.formatException(record.exc_info) if hasattr(self, "formatException") else ""

        doc = LogEvent(
            timestamp=utc_now_iso(),
            level=record.levelname,
            message=msg,
            service=self.service,
            host=self.host,
            environment=self.environment,
            logger=record.name,
            trace_id=ensure_str(fields.pop("trace_id", "")),
            span_id=ensure_str(fields.pop("span_id", "")),
            user_id=ensure_str(fields.pop("user_id", "")),
            tags=fields.pop("tags", []) if isinstance(fields.get("tags", []), list) else [],
            fields=fields,
        ).to_doc()

        try:
            if self.drop_on_full:
                self._q.put_nowait(doc)
            else:
                self._q.put(doc, timeout=0.5)
        except queue.Full:
            return

    def _drain(self, max_items: int) -> List[Dict[str, Any]]:
        items: List[Dict[str, Any]] = []
        for _ in range(max_items):
            try:
                items.append(self._q.get_nowait())
            except queue.Empty:
                break
        return items

    def _run(self) -> None:
        last_flush = time.time()
        buffer: List[Dict[str, Any]] = []
        while not self._stop.is_set():
            timeout = max(0.05, self.flush_interval / 5.0)
            try:
                item = self._q.get(timeout=timeout)
                buffer.append(item)
            except queue.Empty:
                pass

            now = time.time()
            should_flush = (
                len(buffer) >= self.max_batch_size
                or (buffer and (now - last_flush) >= self.flush_interval)
            )
            if should_flush:
                batch = buffer[: self.max_batch_size]
                buffer = buffer[self.max_batch_size :]
                try:
                    self.es_app.bulk_index_logs(batch, refresh=False, index=self.index, chunk_size=self.max_batch_size)
                except Exception:
                    pass
                last_flush = now

        if buffer:
            try:
                self.es_app.bulk_index_logs(buffer, refresh=False, index=self.index, chunk_size=self.max_batch_size)
            except Exception:
                pass

    def flush(self) -> None:
        try:
            items = self._drain(self.max_batch_size)
            if items:
                self.es_app.bulk_index_logs(items, refresh=False, index=self.index, chunk_size=self.max_batch_size)
        except Exception:
            pass

    def close(self) -> None:
        try:
            self._stop.set()
            if self._worker.is_alive():
                self._worker.join(timeout=2.0)
            self.flush()
        finally:
            try:
                super().close()
            except Exception:
                pass


def build_app_from_env() -> ElasticsearchApp:
    url = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
    docs_index = os.getenv("ES_DOCS_INDEX", "documents")
    logs_index = os.getenv("ES_LOGS_INDEX", "logs")
    username = os.getenv("ES_USERNAME")
    password = os.getenv("ES_PASSWORD")
    api_key = os.getenv("ES_API_KEY")

    basic_auth = (username, password) if username and password else None
    api_key_val: Optional[Union[str, Tuple[str, str]]] = api_key if api_key else None

    return ElasticsearchApp(
        hosts=[url],
        index_docs=docs_index,
        index_logs=logs_index,
        index_alias_docs=os.getenv("ES_DOCS_ALIAS", docs_index),
        index_alias_logs=os.getenv("ES_LOGS_ALIAS", logs_index),
        request_timeout=int(os.getenv("ES_REQUEST_TIMEOUT", "30")),
        verify_certs=os.getenv("ES_VERIFY_CERTS", "false").lower() == "true",
        basic_auth=basic_auth,
        api_key=api_key_val,
    )


def _install_signal_handlers(app: ElasticsearchApp, logger: logging.Logger) -> None:
    def _handler(signum, frame):
        try:
            logger.info("Shutting down (signal=%s)", signum)
        except Exception:
            pass
        try:
            app.close()
        finally:
            raise SystemExit(0)

    for s in (signal.SIGINT, signal.SIGTERM):
        try:
            signal.signal(s, _handler)
        except Exception:
            pass


def main() -> None:
    app = build_app_from_env()

    logger = logging.getLogger("centralized")
    logger.setLevel(logging.INFO)
    stream = logging.StreamHandler()
    stream.setLevel(logging.INFO)
    stream.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(name)s - %(message)s"))
    logger.addHandler(stream)

    es_handler = ElasticsearchLogHandler(
        es_app=app,
        service=os.getenv("SERVICE_NAME", "centralized-platform"),
        environment=os.getenv("ENVIRONMENT", "prod"),
        flush_interval=float(os.getenv("ES_LOG_FLUSH_INTERVAL", "1.0")),
        max_batch_size=int(os.getenv("ES_LOG_BATCH_SIZE", "500")),
        max_queue_size=int(os.getenv("ES_LOG_QUEUE_SIZE", "10000")),
        drop_on_full=os.getenv("ES_LOG_DROP_ON_FULL", "true").lower() == "true",
    )
    es_handler.setLevel(logging.INFO)
    logger.addHandler(es_handler)

    _install_signal_handlers(app, logger)

    if not app.ping():
        logger.error("Elasticsearch is not reachable at %s", app.hosts)
        raise SystemExit(2)

    logger.info("Connected to Elasticsearch at %s", app.hosts)

    sample_doc_id = str(uuid.uuid4())
    app.index_document(
        {
            "title": "Centralized Logging Platform",
            "body": "This document describes the centralized logging and full-text search platform backed by Elasticsearch.",
            "tags": ["logging", "search", "elasticsearch"],
            "source": "bootstrap",
            "doc_type": "guide",
        },
        doc_id=sample_doc_id,
        refresh=True,
    )
    logger.info("Indexed sample document id=%s", sample_doc_id)

    res = app.search_documents("centralized logging", size=5)
    hits = res.get("hits", {}).get("hits", [])
    logger.info("Document search hits=%s", len(hits))

    logger.info("Example log event with fields=%s", {"component": "main", "action": "startup"})

    time.sleep(1.5)

    agg = app.aggregate_logs(interval="1m", time_range=("now-15m", "now"))
    logger.info("Log aggregation response keys=%s", list(agg.keys()))

    logger.info("Application running. Press Ctrl+C to exit.")
    while True:
        time.sleep(5)
        logger.info("Heartbeat")


if __name__ == "__main__":
    main()